import json

rules = []
def add(p, r):
    rules.append([p, r])

def IDX(row, col):
    return row * 8 + col

# ==================== CASTLING HELPERS ====================
ALL_CASTLES = ['-', 'K', 'Q', 'k', 'q', 'KQ', 'Kk', 'Kq', 'Qk', 'Qq', 'kq',
               'KQk', 'KQq', 'Kkq', 'Qkq', 'KQkq']

def castle_groups(remove_set, require_set=frozenset()):
    groups = {}
    for c in ALL_CASTLES:
        s = set(c.replace('-', ''))
        if not require_set.issubset(s):
            continue
        new_s = s - remove_set
        new_c = ''.join(x for x in 'KQkq' if x in new_s) or '-'
        if new_c not in groups:
            groups[new_c] = []
        groups[new_c].append(c)
    result = []
    for new_c, old_list in groups.items():
        sorted_olds = sorted(old_list, key=len, reverse=True)
        pattern = '|'.join(sorted_olds)
        result.append((pattern, new_c))
    return result

PASS_CASTLE = castle_groups(frozenset())

def get_castle_gl(src, dst):
    cr = set()
    if src == 60: cr |= {'K', 'Q'}
    if src == 63: cr |= {'K'}
    if src == 56: cr |= {'Q'}
    if dst == 0: cr |= {'q'}
    if dst == 7: cr |= {'k'}
    return castle_groups(cr) if cr else PASS_CASTLE

# ==================== MOVE RULE HELPER ====================
def add_move(src, dst, piece, new_piece=None, capture=False, sliding=False, new_ep='-'):
    if new_piece is None:
        new_piece = piece
    if src == dst:
        return
    tgt = '[a-z]' if capture else '_'
    lo, hi = min(src, dst), max(src, dst)
    btw = hi - lo - 1
    if sliding:
        btw_pat = '(_' + '{' + str(btw) + '})' if btw > 0 else ''
    else:
        btw_pat = '(.' + '{' + str(btw) + '})' if btw > 0 else ''
    if src < dst:
        pre, post = src, 63 - dst
        if btw > 0:
            bp = '(.{%d})(%s)%s(%s)(.{%d})' % (pre, piece, btw_pat, tgt, post)
            gb, db = '\\1\\2\\3\\4\\5', '\\1_\\3%s\\5' % new_piece
            cg, eg = 6, 7
        else:
            bp = '(.{%d})(%s)(%s)(.{%d})' % (pre, piece, tgt, post)
            gb, db = '\\1\\2\\3\\4', '\\1_%s\\4' % new_piece
            cg, eg = 5, 6
    else:
        pre, post = dst, 63 - src
        if btw > 0:
            bp = '(.{%d})(%s)%s(%s)(.{%d})' % (pre, tgt, btw_pat, piece, post)
            gb, db = '\\1\\2\\3\\4\\5', '\\1%s\\3_\\5' % new_piece
            cg, eg = 6, 7
        else:
            bp = '(.{%d})(%s)(%s)(.{%d})' % (pre, tgt, piece, post)
            gb, db = '\\1\\2\\3\\4', '\\1%s_\\4' % new_piece
            cg, eg = 5, 6
    cgl = get_castle_gl(src, dst)
    for cp, cn in cgl:
        pat = '(?m)^G' + bp + ' (' + cp + ') (\\S+)$'
        gr = 'G' + gb + ' \\' + str(cg) + ' \\' + str(eg)
        dr = 'D' + db + ' ' + cn + ' \\' + str(eg)
        add(pat, gr + '\\n' + dr)

# ==================== PHASE 1: FEN PARSE ====================
add(r'^(\S+) w (\S+) (\S+) \d+ \d+$', r'\1 \2 \3')
add('/', '')
for i in range(8, 0, -1):
    add(str(i), '_' * i)
add(r'^', 'G')
print('Phase 1:', len(rules))

# ==================== PHASE 2: MOVE GENERATION ====================
phase2_start = len(rules)

# ---- White Pawn ----
for row in range(1, 7):
    for col in range(8):
        src = IDX(row, col)
        dst = IDX(row - 1, col)
        if row == 1:
            add_move(src, dst, 'P', 'Q', False)
        else:
            add_move(src, dst, 'P', capture=False)
        for dc in [-1, 1]:
            nc = col + dc
            if 0 <= nc < 8:
                d = IDX(row - 1, nc)
                if row == 1:
                    add_move(src, d, 'P', 'Q', True)
                else:
                    add_move(src, d, 'P', capture=True)

print('After pawns:', len(rules))

# ---- Double pawn push (custom 3-position rule) ----
def add_multi_pos(positions_chars, new_values, new_ep='-', castle_gl=None):
    """positions_chars: list of (pos, char_pattern), new_values: list of new chars"""
    if castle_gl is None:
        castle_gl = PASS_CASTLE
    pcs = sorted(zip([p for p, c in positions_chars],
                      [c for p, c in positions_chars],
                      new_values))
    prev = 0
    pat_parts = []
    repl_idxs = []
    gid = 0
    for p, c, n in pcs:
        gap = p - prev
        if gap > 0:
            gid += 1
            pat_parts.append('(.{%d})' % gap)
            repl_idxs.append((gid, None))
        gid += 1
        pat_parts.append('(%s)' % c)
        repl_idxs.append((gid, n))
        prev = p + 1
    tail = 64 - prev
    if tail > 0:
        gid += 1
        pat_parts.append('(.{%d})' % tail)
        repl_idxs.append((gid, None))
    bp = ''.join(pat_parts)
    # G-line: all groups backref
    gb = ''.join('\\' + str(gi) for gi, _ in repl_idxs)
    # D-line: replace specific positions
    db_parts = []
    for gi, nv in repl_idxs:
        if nv is not None:
            db_parts.append(nv)
        else:
            db_parts.append('\\' + str(gi))
    db = ''.join(db_parts)
    cg, eg = gid + 1, gid + 2
    for cp, cn in castle_gl:
        pat = '(?m)^G' + bp + ' (' + cp + ') (\\S+)$'
        gr = 'G' + gb + ' \\' + str(cg) + ' \\' + str(eg)
        dr = 'D' + db + ' ' + cn + ' \\' + str(eg)
        add(pat, gr + '\\n' + dr)

for col in range(8):
    src = IDX(6, col)
    mid = IDX(5, col)
    dst = IDX(4, col)
    ep_str = chr(ord('a') + col) + 'x'
    add_multi_pos([(dst, '_'), (mid, '_'), (src, 'P')],
                  ['P', '_', '_'], new_ep=ep_str)

print('After double push:', len(rules))

# ---- En Passant ----
for col in range(8):
    ep_str = chr(ord('a') + col) + 'y'
