    # EP from right
    if col < 7:
        src_pos = IDX(3, col + 1)
        add_multi_pos([(tgt_pos, '_'), (cap_pos, 'p'), (src_pos, 'P')],
                      ['P', '_', '_'], new_ep='-')

# Hmm, the EP rules above don't check the EP field. I need to match it.
